let selectedState=DATA.states[0].state;
let rankingMetric="exports";
let charts={};

const fmtCompact=new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",notation:"compact",maximumFractionDigits:1});
const fmtFull=new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",maximumFractionDigits:0});

function money(v){return fmtCompact.format(v);}
function moneyFull(v){return fmtFull.format(v);}
function pctValue(v){return v===null||v===undefined?"—":Number(v).toFixed(1)+"%";}
function ordinal(n){if(!n)return "—";const s=["th","st","nd","rd"],v=n%100;return n+(s[(v-20)%10]||s[v]||s[0]);}

document.addEventListener("DOMContentLoaded",()=>{initControls();renderAll();});

function initControls(){
  const stateSelect=document.getElementById("stateSelect");
  stateSelect.innerHTML=DATA.states.slice().sort((a,b)=>a.state.localeCompare(b.state)).map(s=>`<option value="${s.state}">${s.state}</option>`).join("");
  stateSelect.value=selectedState;
  stateSelect.addEventListener("change",e=>{selectedState=e.target.value;renderAll();});
  document.getElementById("metricSelect").addEventListener("change",e=>{rankingMetric=e.target.value;renderStateTable();});
}

function renderAll(){
  renderKpis();
  renderInsights();
  renderNationalProducts();
  renderStateTable();
  renderStateProfile();
}

function renderKpis(){
  const o=DATA.overview;
  const items=[
    ["Exports to EU",o.exports,`${pctValue(o.export_share_pct)} of Brazil's exports`],
    ["Imports from EU",o.imports,`${pctValue(o.import_share_pct)} of Brazil's imports`],
    ["Total trade",o.total_trade,`${pctValue(o.trade_share_pct)} of Brazil's total trade`],
    ["Trade balance",o.balance,"Exports - imports"]
  ];
  document.getElementById("kpis").innerHTML=items.map(([label,value,sub])=>`
    <div class="kpi"><div class="label">${label}</div><div class="value">${money(value)}</div><div class="sub">${sub}</div></div>
  `).join("");
}

function renderInsights(){
  const o=DATA.overview;
  const items=[
    ["Export partner ranking",`EU ranks ${ordinal(o.rank_exports)}`,`EU treated as one partner; non-EU countries counted individually.`],
    ["Import partner ranking",`EU ranks ${ordinal(o.rank_imports)}`,`Based on Brazilian imports from each partner.`],
    ["Overall trade partner ranking",`EU ranks ${ordinal(o.rank_total_trade)}`,`Based on exports + imports.`]
  ];
  document.getElementById("rankCards").innerHTML=items.map(([label,value,sub])=>`
    <div class="insight"><div class="label">${label}</div><div class="value">${value}</div><div class="sub">${sub}</div></div>
  `).join("");
}

function renderStateTable(){
  const rows=DATA.states.slice().sort((a,b)=>b[rankingMetric]-a[rankingMetric]);
  const tbody=document.querySelector("#stateTable tbody");
  tbody.innerHTML=rows.map((r,i)=>`
    <tr data-state="${r.state}" class="${r.state===selectedState?"active":""}">
      <td>${i+1}</td><td>${r.state}</td><td>${money(r.exports)}</td><td>${money(r.imports)}</td><td>${money(r.balance)}</td>
    </tr>
  `).join("");
  tbody.querySelectorAll("tr").forEach(tr=>tr.addEventListener("click",()=>{
    selectedState=tr.dataset.state;
    document.getElementById("stateSelect").value=selectedState;
    renderAll();
  }));
}

function renderStateProfile(){
  const s=DATA.states.find(x=>x.state===selectedState);
  document.getElementById("stateTitle").textContent=`${s.state} and the European Union`;
  document.getElementById("stateKpis").innerHTML=[
    ["Exports to EU",s.exports,`${pctValue(s.export_share_pct)} of ${s.state}'s exports · EU rank: ${ordinal(s.rank_exports)}`],
    ["Imports from EU",s.imports,`${pctValue(s.import_share_pct)} of ${s.state}'s imports · EU rank: ${ordinal(s.rank_imports)}`],
    ["Total trade",s.total_trade,`${pctValue(s.trade_share_pct)} of ${s.state}'s trade · EU rank: ${ordinal(s.rank_total_trade)}`],
    ["Balance",s.balance,s.balance>=0?"Surplus with the EU":"Deficit with the EU"]
  ].map(([label,value,sub])=>`
    <div class="kpi"><div class="label">${label}</div><div class="value">${money(value)}</div><div class="sub">${sub}</div></div>
  `).join("");

  document.getElementById("stateExportsNote").textContent=`“Share of EU trade” shows product composition. “Share traded with the EU” shows the EU’s share of ${s.state}’s worldwide exports of that product.`;
  document.getElementById("stateImportsNote").textContent=`“Share of EU trade” shows product composition. “Share traded with the EU” shows the EU’s share of ${s.state}’s worldwide imports of that product.`;

  const sp=DATA.state_products.filter(d=>d.state===selectedState);
  const topExp=sp.slice().sort((a,b)=>b.exports-a.exports).slice(0,5);
  const topImp=sp.slice().sort((a,b)=>b.imports-a.imports).slice(0,5);

  renderRankingBars("stateExportsRanking",topExp,"exports",s.exports);
  renderRankingBars("stateImportsRanking",topImp,"imports",s.imports);
}

function renderNationalProducts(){
  const topExp=DATA.products.slice().sort((a,b)=>b.exports-a.exports).slice(0,8);
  const topImp=DATA.products.slice().sort((a,b)=>b.imports-a.imports).slice(0,8);

  renderRankingBars("nationalExportsRanking",topExp,"exports",DATA.overview.exports);
  renderRankingBars("nationalImportsRanking",topImp,"imports",DATA.overview.imports);
}


function renderRankingBars(id, rows, metric, denominator){
  const el=document.getElementById(id);
  if(!el)return;

  const productShareKey=metric==="exports"
    ?"eu_share_product_exports_pct"
    :"eu_share_product_imports_pct";

  el.innerHTML=`<div class="product-table">
    <div class="product-table-row product-table-head">
      <div>Rank</div>
      <div>Product</div>
      <div>Value</div>
      <div>Share of EU trade</div>
      <div>Share traded with the EU</div>
    </div>`+
    rows.map((d,i)=>{
      const value=d[metric]||0;
      const compositionShare=denominator?((value/denominator)*100).toFixed(1)+"%":"—";
      const tradedShare=d[productShareKey]===null||d[productShareKey]===undefined
        ?"—"
        :Number(d[productShareKey]).toFixed(1)+"%";
      return `<div class="product-table-row">
        <div class="product-rank">${i+1}</div>
        <div class="product-name">${d.product}</div>
        <div class="product-number">${money(value)}</div>
        <div class="product-number">${compositionShare}</div>
        <div class="product-number product-eu-share">${tradedShare}</div>
      </div>`;
    }).join("")+
    `</div>`;
}

function makeChart(id,config){
  if(charts[id])charts[id].destroy();
  charts[id]=new Chart(document.getElementById(id),config);
}

function barOptions(){
  return {
    indexAxis:"y",
    responsive:true,
    maintainAspectRatio:false,
    plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>moneyFull(ctx.raw)}}},
    scales:{x:{ticks:{callback:v=>money(v)}},y:{ticks:{autoSkip:false}}}
  };
}

function renderProductList(id,rows,metric,title,denominator){
  const el=document.getElementById(id);
  if(!el)return;
  el.innerHTML=`<h4>${title}</h4><ol>`+rows.map(d=>{
    const share=denominator?((d[metric]/denominator)*100).toFixed(1)+"%":"—";
    return `<li><span>${d.product}</span><span class="value">${money(d[metric])}; ${share}</span></li>`;
  }).join("")+`</ol>`;
}

function shortLabel(label){
  label=String(label||"");
  return label.length>42?label.slice(0,42)+"…":label;
}
